// Préparer les emails pour l'analyse AI
const emails = .all().map(item => {
  const d = item.json;
  return {
    id: d.id,
    from: d.from?.text || d.from || 'Unknown',
    subject: d.subject || '(sans objet)',
    date: d.date || d.internalDate || '',
    snippet: (d.snippet || d.textPlain || d.text || '').substring(0, 500),
    labelIds: d.labelIds || []
  };
});

return [{ json: { emails: emails, emailList: JSON.stringify(emails, null, 2) } }];

