let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  // Fallback: essayer d'extraire le JSON
  const match = content.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : { emails: [] };
